const express = require('express');
const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

// JWT verification middleware
function verifyToken(req, res, next) {
  const authHeader = req.headers['authorization'];

  if (!authHeader) {
    return res.status(401).json({ error: 'No authorization header provided' });
  }

  const parts = authHeader.split(' ');

  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return res.status(401).json({ error: 'Authorization header must be in format: Bearer <token>' });
  }

  const token = parts[1];

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = {
      id: decoded.id || decoded.sub,
      email: decoded.email,
      role: decoded.role,
      ...decoded
    };
    // Remove standard JWT claims from the spread to keep it clean
    delete req.user.iat;
    delete req.user.exp;
    delete req.user.nbf;
    delete req.user.iss;
    delete req.user.aud;
    delete req.user.jti;

    // Attach raw decoded token if needed
    req.tokenPayload = decoded;

    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token has expired' });
    }
    if (err.name === 'JsonWebTokenError') {
      return res.status(401).json({ error: 'Invalid token' });
    }
    if (err.name === 'NotBeforeError') {
      return res.status(401).json({ error: 'Token is not yet active' });
    }
    return res.status(401).json({ error: 'Token verification failed' });
  }
}

// Optional: Role-based authorization middleware (use after verifyToken)
function requireRole(...roles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }
    if (!roles.includes(req.user.role)) {
      return res.status(403).json({ error: `Access denied. Required role(s): ${roles.join(', ')}` });
    }
    next();
  };
}

// Helper to generate tokens (for login/signup routes)
function generateToken(payload, expiresIn = '24h') {
  return jwt.sign(payload, JWT_SECRET, { expiresIn });
}

// ---- Demo Express App ----

const app = express();
app.use(express.json());

// Public route - generate a token (simulates login)
app.post('/api/login', (req, res) => {
  const { email, password } = req.body;

  // Simulated user lookup - replace with real DB lookup
  const mockUsers = [
    { id: 1, email: 'admin@example.com', password: 'admin123', role: 'admin', name: 'Admin User' },
    { id: 2, email: 'user@example.com', password: 'user123', role: 'user', name: 'Regular User' }
  ];

  const user = mockUsers.find(u => u.email === email && u.password === password);

  if (!user) {
    return res.status(401).json({ error: 'Invalid email or password' });
  }

  const token = generateToken({
    id: user.id,
    email: user.email,
    role: user.role,
    name: user.name
  });

  res.json({ token, user: { id: user.id, email: user.email, name: user.name, role: user.role } });
});

// Protected route - requires valid JWT
app.get('/api/profile', verifyToken, (req, res) => {
  res.json({
    message: 'Access granted to protected route',
    user: req.user
  });
});

// Protected route - requires admin role
app.get('/api/admin/dashboard', verifyToken, requireRole('admin'), (req, res) => {
  res.json({
    message: 'Welcome to the admin dashboard',
    user: req.user
  });
});

// Protected route - requires admin or moderator role
app.get('/api/moderate', verifyToken, requireRole('admin', 'moderator'), (req, res) => {
  res.json({
    message: 'Moderation panel access granted',
    user: req.user
  });
});

// Public route
